from dataclasses import dataclass, field
from typing import Optional
import openai

client = openai.OpenAI()

@dataclass
class ThoughtNode:
    thought: str
    score: float = 0.0
    depth: int = 0
    parent: Optional["ThoughtNode"] = None
    children: list = field(default_factory=list)

    def path(self) -> list[str]:
        nodes, node = [], self
        while node:
            nodes.append(node.thought)
            node = node.parent
        return list(reversed(nodes))

def propose(problem: str, node: ThoughtNode, k: int = 3) -> list[str]:
    path_text = "\n".join(f"Step {i+1}: {t}" for i, t in enumerate(node.path()))
    prompt = (
        f"Problem: {problem}\n\nReasoning so far:\n{path_text}\n\n"
        f"Generate {k} distinct candidate next steps, one per numbered line."
    )
    resp = client.chat.completions.create(
        model="gpt-4o", temperature=0.7,
        messages=[{"role": "user", "content": prompt}],
    )
    lines = [ln.split(".", 1)[-1].strip() for ln in resp.choices[0].message.content.splitlines() if ln.strip()]
    return lines[:k]

def evaluate(problem: str, node: ThoughtNode, thoughts: list[str]) -> list[float]:
    candidates = "\n".join(f"{i+1}. {t}" for i, t in enumerate(thoughts))
    path_text = "\n".join(node.path())
    prompt = (
        f"Problem: {problem}\n\nPath so far:\n{path_text}\n\n"
        f"Candidates:\n{candidates}\n\n"
        "Rate each candidate 0 (impossible) to 10 (certain correct). One integer per line."
    )
    resp = client.chat.completions.create(
        model="gpt-4o", temperature=0.0,
        messages=[{"role": "user", "content": prompt}],
    )
    scores = []
    for line in resp.choices[0].message.content.strip().splitlines():
        try:
            scores.append(float(line.strip().split()[0]))
        except (ValueError, IndexError):
            scores.append(0.0)
    while len(scores) < len(thoughts):
        scores.append(0.0)
    return scores[:len(thoughts)]

